{
  "family": "Houben-Hoesch Reaction/Synthesis",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "COc1cc(OC)cc(OC)c1"
    ],
    "product_smiles": [
      "CC(=O)c1cc(OC)cc(OC)c1"
    ],
    "optional_reagent_smiles": [
      "Cl[Zn]Cl",
      "Cl"
    ],
    "rationale": "This is a classic textbook example of the Houben-Hoesch reaction, featuring the acylation of a highly activated, electron-rich aromatic ring (1,3,5-trimethoxybenzene) with a simple nitrile (acetonitrile). The reaction is catalyzed by a Lewis acid (ZnCl2) and a protic acid (HCl). The product is a simple aryl ketone, 2,4,6-trimethoxyacetophenone. This example clearly illustrates the key transformation: the formation of a C(aryl)-C(acyl) bond from an arene and a nitrile.",
    "collision_avoidance_note": "This example uses a simple, highly activated arene (1,3,5-trimethoxybenzene) and a simple aliphatic nitrile (acetonitrile). This avoids using generic benzene or phenol, which could collide with Friedel-Crafts acylation or Fries rearrangement, respectively. The use of a nitrile as the acylating agent is the defining characteristic of the Houben-Hoesch reaction, distinguishing it from other electrophilic aromatic acylation reactions."
  }
}
